class Solution {
    public int calculate(String s) {
        int n = s.length();
        Stack<Integer> stack = new Stack<>();
        int currNum = 0;
        char operation = '+';

        for (int i = 0; i < n; i++) {
            char c = s.charAt(i);
            if (Character.isDigit(c)) {
                currNum = currNum * 10 + (c - '0');
            }
            if ((!Character.isDigit(c) && !Character.isWhitespace(c)) || i == n - 1) {
                if (operation == '+') {
                    stack.push(currNum);
                } else if (operation == '-') {
                    stack.push(-currNum);
                } else if (operation == '*') {
                    stack.push(stack.pop() * currNum);
                } else if (operation == '/') {
                    stack.push(stack.pop() / currNum);
                }
                operation = c;
                currNum = 0;
            }
        }
        int res = 0;
        while (!stack.isEmpty()) {
            res += stack.pop();
        }
        return res;
    }
}
